// Handle Meta webhook verification (GET)
const query = $input.first().json.query || {};
const verifyToken = 'flowbot_verify_token'; // must match what you set in Meta portal

if (query['hub.mode'] === 'subscribe' && query['hub.verify_token'] === verifyToken) {
  return [{ json: { challenge: query['hub.challenge'] } }];
}

return [{ json: { error: 'Invalid verify token' } }];

const body = $input.first().json.body || $input.first().json;

// ── Signature verification (recommended in production) ──
// const crypto = require('crypto');
// const appSecret = process.env.WA_APP_SECRET || '';
// const signature = $input.first().json.headers?.['x-hub-signature-256'] || '';
// const expected = 'sha256=' + crypto.createHmac('sha256', appSecret).update(JSON.stringify(body)).digest('hex');
// if (appSecret && signature !== expected) throw new Error('Invalid signature');

// ── Parse WhatsApp payload ──────────────────────────────
const entry  = body.entry?.[0];
const change = entry?.changes?.[0];
const value  = change?.value;

// Ignore non-message webhooks (status updates, etc)
if (!value?.messages) {
  return [{ json: { skip: true, reason: 'No message in payload' } }];
}

const message       = value.messages[0];
const phoneNumberId = value.metadata?.phone_number_id;
const from          = message.from;        // customer's phone number
const messageType   = message.type;
const messageId     = message.id;

if (!phoneNumberId) {
  throw new Error('No phone_number_id in payload — cannot route to tenant');
}

const baseOut = {
  from,
  phoneNumberId,
  messageId,
  sessionId:     from,        // use customer phone as session ID
  channel:       'whatsapp',
  timestamp:     new Date().toISOString(),
  // media defaults (text path leaves these untouched)
  isImageSearch: false,
  hasMedia:      false,
  mediaKind:     null,
  mediaId:       null,
  mediaMime:     null,
  mediaFilename: null
};

// ── TEXT message ────────────────────────────────────────
if (messageType === 'text') {
  const text = message.text?.body || '';
  if (!text.trim()) return [{ json: { skip: true, reason: 'Empty message' } }];
  return [{ json: { ...baseOut, rawMessage: text } }];
}

// ── IMAGE message → product IMAGE SEARCH ────────────────
// WhatsApp delivers images as jpeg / png / webp. We accept any image/* and
// default the mime to jpeg so low-quality / odd uploads are handled gracefully.
if (messageType === 'image') {
  const img  = message.image || {};
  const mime = (img.mime_type || 'image/jpeg').toLowerCase();
  if (img.id) {
    return [{ json: {
      ...baseOut,
      rawMessage:    (img.caption || '').trim(), // caption is an extra text hint (may be empty)
      isImageSearch: true,
      hasMedia:      true,
      mediaKind:     'image',
      mediaId:       img.id,
      mediaMime:     mime
    } }];
  }
  return [{ json: { skip: true, reason: 'Image message without media id', phoneNumberId, from } }];
}

// ── DOCUMENT message (PDF payment slip etc.) ────────────
if (messageType === 'document') {
  const doc  = message.document || {};
  const mime = (doc.mime_type || 'application/pdf').toLowerCase();
  if (doc.id) {
    return [{ json: {
      ...baseOut,
      rawMessage:    (doc.caption || doc.filename || '').trim(),
      isImageSearch: false,
      hasMedia:      true,
      mediaKind:     'document',
      mediaId:       doc.id,
      mediaMime:     mime,
      mediaFilename: doc.filename || null
    } }];
  }
  return [{ json: { skip: true, reason: 'Document message without media id', phoneNumberId, from } }];
}

// ── Any other type (audio / video / sticker / location …) ──
return [{ json: { skip: true, reason: `Unsupported message type: ${messageType}`, phoneNumberId, from } }];

const parsed    = $('Code — Parse WA Message').first().json;
const tenantRes = $('HTTP — Get Tenant by Phone ID').first().json;

if (!tenantRes.tenant) {
  throw new Error(`No tenant found for phone_number_id: ${parsed.phoneNumberId}`);
}
const tenant = tenantRes.tenant;
const msg = (parsed.rawMessage || '').toLowerCase();

// ── Language rules + system base ────────────────────────────────────
const langRules = {
  SI: 'Reply ONLY in Sinhala script (Unicode). Do not use English.',
  TA: 'Reply ONLY in Tamil script (Unicode). Do not use English.',
  SL: 'Reply ONLY in Singlish — Sinhala words written in English letters. Do NOT use Sinhala Unicode.',
  EN: 'Reply in English.'
};
const systemBase = tenant.system_prompt ||
  `You are ${tenant.bot_name || 'FlowBot'}, a friendly AI assistant for ${tenant.business_name}. Sound natural and human. Keep replies concise. Never say you are an AI unless directly asked.`;

// ── Helpers (used for the LLM query + the slim fallback) ────────────
const STOPWORDS = new Set(['the','a','an','is','are','do','you','have','any','show','me','please','can','i','want',
  'to','of','for','with','and','or','in','on','my','your','this','that','it','what','whats','need','looking','look',
  'some','give','send','see','got','pls','plz','hi','hello','hey','there','about','tell','will','would','could','get',
  'find','search','all','products','product','items','item','catalog','catalogue','collection','everything','stuff',
  'range','list','ones','things','thing','available','ur','u','wanna','gimme','lemme','wat','wats',
  'image','images','photo','photos','picture','pictures','pic','pics','asking','ask']);
function tokenize(s) {
  return (s || '').toLowerCase().replace(/[^a-z0-9\s-]/g, ' ').split(/\s+/)
    .filter(w => w.length >= 2 && !STOPWORDS.has(w));
}
function parsePriceRange(text) {
  const t = (text || '').replace(/,/g, '').toLowerCase();
  let m;
  if ((m = t.match(/(?:between|from)\s*(?:rs\.?|lkr)?\s*(\d{2,7})\s*(?:and|to|-|–|—)\s*(?:rs\.?|lkr)?\s*(\d{2,7})/))) return { min: +m[1], max: +m[2] };
  if ((m = t.match(/(?:under|below|less than|cheaper than|max|upto|up to|within|no more than)\s*(?:rs\.?|lkr)?\s*(\d{2,7})/))) return { min: null, max: +m[1] };
  if ((m = t.match(/(?:over|above|more than|min|minimum|at least|starting (?:from|at))\s*(?:rs\.?|lkr)?\s*(\d{2,7})/))) return { min: +m[1], max: null };
  if ((m = t.match(/(?:around|about|approx\.?|approximately|near|~)\s*(?:rs\.?|lkr)?\s*(\d{2,7})/))) { const v = +m[1]; return { min: Math.round(v*0.8), max: Math.round(v*1.2) }; }
  return { min: null, max: null };
}
const sriLankaCities = ['colombo','kandy','galle','jaffna','negombo','matara','kurunegala','anuradhapura','polonnaruwa',
  'badulla','nuwara eliya','ratnapura','batticaloa','trincomalee','vavuniya','puttalam','chilaw','horana','panadura',
  'moratuwa','dehiwala','maharagama','nugegoda','kaduwela','malabe','rajagiriya','kelaniya','wattala','gampaha',
  'kiribathgoda','weligama','ambalangoda','hikkaduwa','tangalle','hambantota','embilipitiya','dambulla'];
function titleCase(s) { return String(s || '').split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' '); }
const COLORS = ['black','white','red','blue','green','yellow','pink','purple','orange','brown','grey','gray','navy',
  'maroon','gold','silver','beige','cream','teal','olive','mustard','peach','lavender'];

// ── PRIMARY: structured understanding from the LLM ──────────────────
let u = null;
try {
  const content = $('LLM — Understand').first().json.candidates?.[0]?.content?.parts?.[0]?.text || '';
  u = JSON.parse(content.replace(/```json|```/g, '').trim());
} catch (e) { u = null; }

// ── FALLBACK (slim safety net): only runs if the LLM call fails ─────
let usedFallback = false;
if (!u || typeof u !== 'object') {
  usedFallback = true;
  const pr = parsePriceRange(parsed.rawMessage);
  let fcity = null;
  for (const c of sriLankaCities) { if (msg.includes(c)) { fcity = titleCase(c); break; } }
  const ord    = /\b(order|checkout|buy now|place (?:an |the )?order|confirm order|i want to buy|add to cart|i want this|take this)\b/.test(msg);
  const cats   = /\b(categor(?:y|ies)|what (?:types|kinds))\b/.test(msg);
  const browse = /\b(everything|all products|catalog(?:ue)?|collection|show me all|what (?:do|have) you (?:got|have|sell))\b/.test(msg);
  const prod   = /\b(price|cost|how much|buy|saree|frock|dress|gown|shirt|tshirt|t-shirt|top|shoe|bag|skirt|denim|size|colou?r|stock|available|show|photo|item)\b/.test(msg);
  const del    = /\b(deliver|delivery|shipping|ship|courier)\b/.test(msg) || (!!fcity && !prod);
  let fsize = null;
  let sm = msg.match(/\bsize\s*([a-z0-9]{1,4})\b/) || msg.match(/\b([sml])\s*size\b/) || msg.match(/\b(xs|xl|xxl|xxxl)\b/);
  if (sm) fsize = sm[1].toUpperCase();
  let fcolor = null;
  for (const c of COLORS) { if (new RegExp('\\b' + c + '\\b').test(msg)) { fcolor = c; break; } }
  u = {
    intent:     cats ? 'categories' : ord ? 'order' : (prod || browse) ? 'product' : del ? 'delivery' : 'general',
    wantsImage: /\b(photo|image|pic|see|show|send)\b/.test(msg),
    city:       fcity,
    search: {
      query:       (prod || browse) ? tokenize(parsed.rawMessage).join(' ') : '',
      minPrice:    pr.min, maxPrice: pr.max,
      inStockOnly: /\b(in stock|available)\b/.test(msg),
      browseAll:   browse,
      size:        fsize,
      color:       fcolor,
      skus:        ((parsed.rawMessage || '').match(/\b[a-z]{1,5}[-_]?\d{2,6}\b/gi) || []).map(s => s.toUpperCase())
    }
  };
}

// ── Language: trust the LLM if valid, else fall back to script detection ──
const LANGMAP = { EN: 'English', SI: 'Sinhala', TA: 'Tamil', SL: 'Singlish' };
let langCode = String(u.language || '').toUpperCase();
if (!LANGMAP[langCode]) {
  if (/[\u0D80-\u0DFF]/.test(parsed.rawMessage || '')) langCode = 'SI';
  else if (/[\u0B80-\u0BFF]/.test(parsed.rawMessage || '')) langCode = 'TA';
  else langCode = 'EN';
}
const lang = { code: langCode, label: LANGMAP[langCode] || 'English' };

// ── Deterministic SAFETY NET: hard handoff on configured trigger words ──
const rawHandoff = tenant.handoff_words || tenant.handoff_triggers || 'speak to human,manager,call me,urgent,agent,human,real person';
const handoffWords = (Array.isArray(rawHandoff) ? rawHandoff : String(rawHandoff).split(','))
  .map(w => String(w).trim().toLowerCase()).filter(Boolean);
const hardHandoff = handoffWords.some(w => msg.includes(w));

// ── Map understanding → the flags the rest of the workflow expects ──
const isImageSearch  = !!parsed.isImageSearch;            // an actual uploaded photo (deterministic)
const llmIntent      = String(u.intent || 'general').toLowerCase();
const isHandoff      = hardHandoff || llmIntent === 'handoff';
const isCategoryQuery = llmIntent === 'categories' || /\b(categor(?:y|ies)|what (?:types|kinds))\b/.test(msg);
const detectedCity   = u.city ? titleCase(u.city) : null;
const isOrderIntent  = llmIntent === 'order';
const sObj           = u.search || {};
const browseAll      = (!!sObj.browseAll || llmIntent === 'browse') && !isCategoryQuery;
const hasQuery       = !!(sObj.query && String(sObj.query).trim()) || browseAll || (Array.isArray(sObj.skus) && sObj.skus.length > 0);
const effProductIntent = (isImageSearch || ['product', 'browse'].includes(llmIntent) || hasQuery) && !isCategoryQuery;
const isDeliveryIntent = llmIntent === 'delivery'
  || (!!detectedCity && !['product', 'image', 'order', 'browse'].includes(llmIntent) && !effProductIntent && !isCategoryQuery);

const search = {
  query:       sObj.query || '',
  tokens:      tokenize(sObj.query || ''),
  skus:        Array.isArray(sObj.skus) ? sObj.skus.map(s => String(s).toUpperCase()) : [],
  minPrice:    (sObj.minPrice ?? null),
  maxPrice:    (sObj.maxPrice ?? null),
  inStockOnly: !!sObj.inStockOnly,
  browseAll:   browseAll,
  category:    sObj.category || null,
  brand:       sObj.brand || null,
  size:        sObj.size ? String(sObj.size).trim() : null,
  color:       (sObj.color || sObj.colour) ? String(sObj.color || sObj.colour).trim() : null
};
const wantsImage = (!!u.wantsImage
  || /\b(photo|photos|image|images|pic|pics|picture|pictures)\b/.test(msg)
  || /\bshow\b/.test(msg)) && !browseAll;

// ── ORDER STATUS DETECTION (deterministic — never trust cached/assumed status) ──
const orderRefMatch = (parsed.rawMessage || '').match(/ORD[-\s]?\d{4}[-\s]?\d{3,}/i);
const orderRef = orderRefMatch
  ? orderRefMatch[0].toUpperCase().replace(/\s+/g, '-').replace(/-+/g, '-')
  : '';
// Strong status phrasing OVERRIDES the LLM even if it mislabels this as a new 'order'.
const strongStatus =
  /\border\s+status\b/i.test(msg) ||
  /\bstatus\s+of\s+(?:my\s+|the\s+)?order\b/i.test(msg) ||
  /\bwhere(?:'?s| is)\s+(?:my|the)\s+order\b/i.test(msg) ||
  /\btrack(?:ing)?\s+(?:my\s+|the\s+)?order\b/i.test(msg) ||
  /\bwhen\s+will\s+(?:my|the)\s+order\b/i.test(msg) ||
  /\b(?:has\s+)?(?:my|the)\s+order\s+(?:shipped|been\s+\w+)\b/i.test(msg) ||
  /\border\s+update\b/i.test(msg);
const softStatus = /\bmy\s+order\b/i.test(msg);
const isOrderStatus =
  (llmIntent === 'order_status') || !!orderRef || strongStatus || (softStatus && !isOrderIntent);

const intent = isImageSearch ? 'image_search'
             : isOrderStatus ? 'order_status'
             : isCategoryQuery ? 'categories'
             : isOrderIntent ? 'order'
             : effProductIntent ? 'product_inquiry'
             : isDeliveryIntent ? 'delivery_inquiry'
             : isHandoff ? 'handoff'
             : 'general';

return [{ json: {
  sessionId:     parsed.from,
  userMessage:   parsed.rawMessage,
  from:          parsed.from,
  phoneNumberId: parsed.phoneNumberId,
  messageId:     parsed.messageId,
  channel:       'whatsapp',
  timestamp:     parsed.timestamp,
  tenantId:      tenant.id,
  understandTokens: ($('LLM — Understand').first().json.usageMetadata?.totalTokenCount || 0),
  waAccessToken: tenant.wa_access_token,
  botName:       tenant.bot_name || 'FlowBot',
  systemBase,
  lang:          lang.code,
  langLabel:     lang.label,
  langRule:      langRules[lang.code] || langRules.EN,
  isHandoff,
  isProductIntent: effProductIntent,
  isDeliveryIntent,
  isOrderIntent,
  isCategoryQuery,
  detectedCity,
  intent,
  orderRef,
  isOrderStatus,
  search,
  wantsImage,
  isImageSearch,
  hasMedia:      parsed.hasMedia,
  mediaKind:     parsed.mediaKind,
  mediaId:       parsed.mediaId,
  mediaMime:     parsed.mediaMime,
  mediaFilename: parsed.mediaFilename,
  understoodBy: usedFallback ? 'keyword_fallback' : 'llm'
} }];

const data = $('Code — Detect Language + Route').first().json;

const handoffMsgs = {
  EN: `Thank you for reaching out! A member of our team will contact you shortly. \n\nBusiness hours: Mon-Sat 9am-6pm`,
  SI: `ඔබගේ පණිවිඩයට ස්තූතියි! අපගේ කණ්ඩායමේ සාමාජිකයෙකු ඉක්මනින් ඔබව සම්බන්ධ කර ගනු ඇත.`,
  TA: `தொடர்பு கொண்டதற்கு நன்றி! எங்கள் குழு உறுப்பினர் விரைவில் தொடர்பு கொள்வார்கள்.`,
  SL: `Thank you! Api team eka soon contact karanawa. Bohoma stutiy!`
};

return [{ json: {
  ...data,
  botReply: handoffMsgs[data.lang] || handoffMsgs.EN
} }];

const base = $('Code — Detect Language + Route').first().json;

// ── CHAT HISTORY ────────────────────────────────────────────────
const historyRes  = $('HTTP — Get Chat History').first().json;
const chatHistory = (historyRes.history || []).slice(-20); // last 20 messages
// Was an order already placed/confirmed earlier in THIS conversation? (prevents
// the model re-firing ###PLACE_ORDER### on greetings, thanks, or status questions)
const ORDER_DONE_MARK = /(Order ID|ඇණවුම් අංකය|ஆர்டர் எண්|order eka confirm|ORD[-\s]?\d{4}[-\s]?\d{3,}|payment slip|verifying your payment|payment reference)/i;
const alreadyOrdered = chatHistory.slice(-6).some(m => m.role === 'assistant' && ORDER_DONE_MARK.test(m.content || ''));
const userMsg     = base.userMessage.toLowerCase();

// ── CURRENT ORDER STATE (live, for edit-permission decisions) ──────
let orderState = 'unknown';   // none | editable | locked | cancelled | unknown
let supportNumber = '';
let currentOrderRef = null;
try {
  const co = $('Code — Normalize Current Order').first().json || {};
  orderState = co.orderState || 'unknown';
  supportNumber = (co.supportNumber || '').trim();
  currentOrderRef = co.currentOrderRef || null;
} catch (e) {}

// normalisers
const normWords = s => (s || '').toLowerCase().replace(/[^a-z0-9\s]/g, ' ').replace(/\s+/g, ' ').trim();
const normTight = s => (s || '').toLowerCase().replace(/[^a-z0-9]/g, '');

// ── DYNAMIC CONFIG (from /api/v1/n8n/webhook get_config) ─────────
let chatbotSettings = {};
try { chatbotSettings = $('HTTP — n8n get_config').first().json.chatbot_settings || {}; } catch (e) {}
const fallbackMsg = chatbotSettings.fallback_message
  || 'No specific info available. Tell the customer to contact the team directly.';

// ── KB CONTEXT ──────────────────────────────────────────
const entries = $('HTTP — GET /api/v1/kb').first().json.entries || [];
let bestMatch = null, bestScore = 0;
for (const entry of entries) {
  const keywords = Array.isArray(entry.keywords)
    ? entry.keywords.map(k => k.toLowerCase())
    : (entry.keywords || '').toLowerCase().split(',').map(k => k.trim());
  const question = (entry.question || '').toLowerCase();
  const category = (entry.category || '').toLowerCase();
  const answer   = (entry.answer   || '').toLowerCase();
  let score = 0;
  for (const kw of keywords) { if (kw && userMsg.includes(kw)) score += 3; }
  const userWords = userMsg.split(/\s+/).filter(w => w.length > 2);
  for (const word of userWords) {
    if (question.includes(word)) score += 2;
    if (category.includes(word)) score += 1;
    if (answer.includes(word))   score += 1;
  }
  if (score > bestScore) { bestScore = score; bestMatch = entry; }
}
let kbContext = '';
if (bestMatch && bestScore >= 2) {
  kbContext = `RELEVANT FAQ:\nCategory: ${bestMatch.category}\nQ: ${bestMatch.question}\nA: ${bestMatch.answer}`;
} else if (entries.length > 0) {
  const top = entries.slice(0, 10).map(e => `[${e.category}] ${e.question} → ${e.answer}`).join('\n');
  kbContext = `COMPANY FAQ:\n${top}`;
}

// ══════════════════════════════════════════════════════════════════
//  PRODUCT SEARCH ENGINE  (text + image, typo-tolerant, ranked)
// ══════════════════════════════════════════════════════════════════

// Damerau–Levenshtein distance (typo tolerance)
function dlDistance(a, b) {
  a = a || ''; b = b || '';
  const al = a.length, bl = b.length;
  if (!al) return bl; if (!bl) return al;
  const d = Array.from({ length: al + 1 }, () => new Array(bl + 1).fill(0));
  for (let i = 0; i <= al; i++) d[i][0] = i;
  for (let j = 0; j <= bl; j++) d[0][j] = j;
  for (let i = 1; i <= al; i++) {
    for (let j = 1; j <= bl; j++) {
      const cost = a[i - 1] === b[j - 1] ? 0 : 1;
      d[i][j] = Math.min(d[i - 1][j] + 1, d[i][j - 1] + 1, d[i - 1][j - 1] + cost);
      if (i > 1 && j > 1 && a[i - 1] === b[j - 2] && a[i - 2] === b[j - 1])
        d[i][j] = Math.min(d[i][j], d[i - 2][j - 2] + 1);
    }
  }
  return d[al][bl];
}

// fuzzy match of one query token against one normalised field
function fuzzyHit(token, fieldWords, fieldTight) {
  if (!token) return 0;
  if (fieldWords === token || (' ' + fieldWords + ' ').includes(' ' + token + ' ')) return 1;   // exact word
  if (fieldTight && fieldTight.includes(normTight(token))) return 0.95;                          // hyphen/partial
  for (const fw of fieldWords.split(' ')) {
    if (!fw) continue;
    if (fw.startsWith(token) || token.startsWith(fw)) return 0.9;                                // prefix
    const maxd = token.length <= 4 ? 1 : 2;
    if (Math.abs(fw.length - token.length) <= maxd && dlDistance(token, fw) <= maxd) return 0.8; // typo
  }
  return 0;
}

// light synonym expansion (extendable)
const SYN = {
  tshirt: ['tee', 'tshirt', 'shirt'], frock: ['dress', 'dresses', 'gown', 'gowns', 'frock', 'frocks'], saree: ['sari', 'saree', 'sarees'],
  trouser: ['pant', 'pants', 'trousers'], shoe: ['shoes', 'footwear', 'sneaker', 'sneakers'],
  kid: ['child', 'children', 'kids'], men: ['mens', 'man', 'gents', 'gent'],
  women: ['womens', 'woman', 'ladies', 'lady'], cheap: ['budget', 'affordable']
};
function expandTokens(tokens) {
  const out = new Set(tokens.map(t => t.replace(/[^a-z0-9]/g, '')));
  for (const t of tokens) {
    for (const [k, vs] of Object.entries(SYN)) {
      if (k === t || vs.includes(t)) { out.add(k); vs.forEach(v => out.add(v.replace(/[^a-z0-9]/g, ''))); }
    }
  }
  return [...out].filter(Boolean);
}

const FIELD_W = { name: 5, sku: 6, brand: 3, keywords: 3, category: 2, description: 1 };

function buildFields(p) {
  const kw = Array.isArray(p.keywords) ? p.keywords.join(' ')
           : Array.isArray(p.tags)     ? p.tags.join(' ')
           : (p.keywords || p.tags || '');
  const raw = {
    name: p.name || '', sku: p.sku || '', brand: p.brand || '',
    keywords: kw, category: p.category || '', description: p.description || ''
  };
  const words = {}, tight = {};
  for (const k in raw) { words[k] = normWords(raw[k]); tight[k] = normTight(raw[k]); }
  return { words, tight };
}

function scoreProduct(fields, qTokens) {
  let score = 0, matched = 0;
  for (const t of qTokens) {
    let best = 0;
    for (const [f, w] of Object.entries(FIELD_W)) {
      const hit = fuzzyHit(t, fields.words[f], fields.tight[f]);
      if (hit > 0) best = Math.max(best, hit * w);
    }
    if (best > 0) matched++;
    score += best;
  }
  if (qTokens.length) score *= (0.6 + 0.4 * (matched / qTokens.length)); // coverage bonus
  return score;
}

function priceOf(p) {
  if (p.base_price != null) return Number(p.base_price) || 0;
  const vs = p.variants || [];
  const prices = vs.map(v => Number(v.price) || 0).filter(Boolean);
  return prices.length ? Math.min(...prices) : 0;
}
function inStockOf(p) {
  const vs = p.variants || [];
  return vs.length ? vs.some(v => (v.stock || 0) > 0) : (p.stock || 0) > 0;
}
function passFilters(p, s) {
  const price = priceOf(p);
  if (s.minPrice != null && price < s.minPrice) return false;
  if (s.maxPrice != null && price > s.maxPrice) return false;
  if (s.inStockOnly && !inStockOf(p)) return false;
  return true;
}

// render the price/variant line (NEVER reveals quantities)
function stockLine(p) {
  const vs = p.variants || [];
  if (vs.length) {
    const inStock = vs.filter(v => (v.stock || 0) > 0);
    if (!inStock.length) return 'Out of stock';
    return inStock.map(v => {
      const label = `${v.size || ''}${v.size && (v.color_name || v.colour_name) ? '/' : ''}${v.color_name || v.colour_name || ''}`;
      return `${label}: LKR ${(v.price || p.base_price || 0).toLocaleString()}`;
    }).join(', ');
  }
  return (p.stock || 0) > 0 ? `LKR ${(p.base_price || 0).toLocaleString()}` : 'Out of stock';
}

// ── VARIANT MATCHING (size / colour) ──
const _nc = s => String(s || '').toLowerCase().trim();
function variantMatches(v, size, color) {
  if (size  && _nc(v.size) !== _nc(size)) return false;
  if (color) {
    const cv = _nc(v.color_name || v.colour_name);
    if (!cv.includes(_nc(color)) && !_nc(color).includes(cv)) return false;
  }
  return true;
}
function bestVariant(p, size, color) {
  const vs = p.variants || [];
  const cands = vs.filter(v => variantMatches(v, size, color));
  const inStock = cands.filter(v => (v.stock || 0) > 0);
  if (inStock.length) return { v: inStock[0], inStock: true,  matched: true };
  if (cands.length)   return { v: cands[0],   inStock: false, matched: true };
  return { v: null, inStock: false, matched: false };
}
function variantLine(p, size, color) {
  const bv = bestVariant(p, size, color);
  if (bv.v && bv.matched) {
    const label = [bv.v.size, bv.v.color_name || bv.v.colour_name].filter(Boolean).join(' / ');
    return bv.inStock
      ? `${label} — LKR ${(bv.v.price || p.base_price || 0).toLocaleString()}`
      : `${label} — out of stock`;
  }
  return stockLine(p);
}

// ── Gather the catalog (already fetched, optionally pre-filtered server-side) ──
const products = $('HTTP — GET /api/v1/products').first().json.products || [];

// image-search results (always present — inert on the text path)
let imgRes = { isImageSearch: false, matches: [], visionKeywords: [], unavailable: false };
try { imgRes = $('Code — Image Search Results').first().json || imgRes; } catch (e) {}

let productContext   = '';
let pendingImageUrl  = null;     // decided in code, NOT by the LLM
let pendingImageCaption = '';
let searchResults    = [];       // ranked, for analytics / downstream
let searchMode       = 'none';
let noMatch          = false;
let stockAsk         = false;    // customer asked about availability alongside a photo
let topMatchOOS      = false;    // the closest visual match is out of stock
let isBrowse         = false;    // "show me everything" — list the catalogue
let wantSize         = null;     // requested size (e.g. M)
let wantColor        = null;     // requested colour
let sizeColorOOS     = false;    // asked size/colour exists but is out of stock
let sizeNotCarried   = false;    // we have the item but not that size/colour

const wantsImage = (base.wantsImage != null) ? !!base.wantsImage
  : ['photo', 'image', 'picture', 'pic', 'see', 'show', 'send'].some(w => userMsg.includes(w));

if (base.isImageSearch || base.isProductIntent || base.isOrderIntent) {

  let ranked = [];   // [{ p, score, sim }]

  // ───────────── IMAGE SEARCH (+ caption refinement) ─────────────
  if (base.isImageSearch) {
    searchMode = 'image';
    const s = base.search || { tokens: [], skus: [] };
    const capTokens = expandTokens(s.tokens || []);   // words typed alongside the photo

    const byId   = {}; products.forEach(p => { if (p.id != null) byId[String(p.id)] = p; });
    const byName = {}; products.forEach(p => { byName[normTight(p.name)] = p; });

    if (imgRes.matches && imgRes.matches.length) {
      // visual-similarity endpoint hit → enrich each match with live catalog price/stock
      ranked = imgRes.matches.map(m => {
        const p = byId[String(m.product_id)] || byName[normTight(m.name)]
                || { name: m.name, image_urls: m.image_url ? [m.image_url] : [], _unresolved: true };
        return { p, score: m.similarity_score, sim: m.similarity_score };
      });
    }
    // STRICT: no vision-keyword fuzzy fallback. If embeddings returned nothing
    // confident, "ranked" stays empty and we tell the customer we don't stock it.

    // Caption words (e.g. "in red", "size M") nudge the visual ranking — they
    // refine WHICH visual match, they don't replace the photo signal.
    if (capTokens.length) {
      ranked = ranked.map(x => {
        const bonus = x.p._unresolved ? 0 : scoreProduct(buildFields(x.p), capTokens);
        return { ...x, score: (x.score || 0) + bonus * 0.5 };
      });
    }

    // Price asked alongside the photo → keep only in-range matches (if any survive).
    if (s.minPrice != null || s.maxPrice != null) {
      const inRange = ranked.filter(x => x.p._unresolved
        || passFilters(x.p, { minPrice: s.minPrice, maxPrice: s.maxPrice }));
      if (inRange.length) ranked = inRange;
    }

    // "Is this in stock?" → keep the exact match first (so the customer sees the
    // item they asked about + its status); flag when that closest match is OOS so
    // the bot can offer a similar in-stock alternative.
    if (s.inStockOnly) {
      stockAsk = true;
      const topVisual = ranked.slice().sort((a, b) => (b.score || 0) - (a.score || 0))[0];
      topMatchOOS = topVisual ? !inStockOf(topVisual.p) : false;
    }

    ranked.sort((a, b) => (b.score || 0) - (a.score || 0));
  }

  // ───────────── TEXT SEARCH ─────────────
  if (!base.isImageSearch) {
    searchMode = 'text';
    const s = base.search || { tokens: [], skus: [] };
    const qTokens = expandTokens(s.tokens || []);
    const wantsAll = !!s.browseAll;
    const hasQuery = !wantsAll && (qTokens.length > 0 || (s.skus || []).length > 0);
    isBrowse = wantsAll || !hasQuery;   // "see all products" / no specific keyword → browse the catalogue

    // hard filters (price / availability); relax if they empty the catalog
    let filtered = products.filter(p => passFilters(p, s));
    if (filtered.length === 0 && (s.minPrice != null || s.maxPrice != null || s.inStockOnly)) filtered = products;

    const skuSet = new Set((s.skus || []).map(x => x.toLowerCase()));
    const scored = filtered.map(p => {
      const f = buildFields(p);
      let sc = scoreProduct(f, qTokens);
      if (skuSet.has(String(p.sku || '').toLowerCase())) sc += 20; // exact SKU wins
      return { p, score: sc, sim: null };
    }).sort((a, b) => (b.score - a.score) || (inStockOf(b.p) - inStockOf(a.p)) || (priceOf(a.p) - priceOf(b.p)));

    ranked = hasQuery ? scored.filter(x => x.score > 0) : scored; // browse → whole (filtered) catalogue

    // size / colour refinement — keep products that actually carry the variant
    wantSize  = (base.search && base.search.size)  ? String(base.search.size).trim()  : null;
    wantColor = (base.search && base.search.color) ? String(base.search.color).trim() : null;
    if ((wantSize || wantColor) && ranked.length) {
      const tagged = ranked.map(x => ({ x, bv: bestVariant(x.p, wantSize, wantColor) }));
      const inStock = tagged.filter(t => t.bv.matched && t.bv.inStock);
      const oos     = tagged.filter(t => t.bv.matched && !t.bv.inStock);
      if (inStock.length)    { ranked = inStock.map(t => t.x); }
      else if (oos.length)   { ranked = oos.map(t => t.x); sizeColorOOS = true; }
      else                   { sizeNotCarried = true; } // matched the item, not that size/colour
    }
  }

  // ───────────── RENDER ─────────────
  const top = ranked.slice(0, isBrowse ? 8 : 5);
  searchResults = top.map(x => ({
    name: x.p.name, price: priceOf(x.p), in_stock: inStockOf(x.p),
    score: Math.round((x.score || 0) * 100) / 100,
    similarity: x.sim != null ? Math.round(x.sim * 1000) / 1000 : null
  }));

  if (top.length === 0) {
    noMatch = true;
    if (searchMode === 'image') {
      productContext = imgRes.unavailable
        ? `IMAGE SEARCH FAILED (system/quality issue): We could not process this photo. Politely apologise and ask the customer to resend a clear, well-lit photo of the single item, or to type the product name. Do NOT say whether we stock it — we could not check.`
        : `IMAGE SEARCH — NO MATCH: This photo does NOT match any product we sell.
STRICT RULES (no guessing):
- Tell the customer plainly and politely that we do NOT have this product and don't sell anything like it.
- Do NOT show, name, suggest, describe, or price ANY product. Do NOT offer "similar" or "related" items.
- Do NOT guess what the item might be. Do NOT invent products, prices, or availability.
- You may briefly invite them to type a product name or ask what we sell — nothing more.`;
    } else {
      const asked = (base.search && base.search.query) ? base.search.query : base.userMessage;
      productContext = `PRODUCT SEARCH: We do NOT stock "${asked}". Nothing in the catalogue matches it.
RULES:
- Tell the customer plainly and politely that we don't have "${asked}".
- Do NOT say we have it, do NOT offer its price, and do NOT take an order for it.
- Do NOT switch to a different product and present it as if it were the one they asked for.
- You may offer to show the kinds of items we DO sell (by category), but never invent items.
- Never invent products, prices, or availability — even if the customer insists.`;
    }
  } else {
    const lines = top.map(x => {
      const tag = x.sim != null ? ` (match ${Math.round(x.sim * 100)}%)` : '';
      const priceInfo = (wantSize || wantColor) ? variantLine(x.p, wantSize, wantColor) : stockLine(x.p);
      return `• ${x.p.name}${tag}: ${priceInfo}`;
    }).join('\n');
    const heading = searchMode === 'image'
      ? `MATCHED PRODUCT(S) FROM OUR CATALOGUE (the customer's photo matches these — present the best one as the item):`
      : isBrowse
        ? `OUR PRODUCTS (showing a selection — ask for a type, colour or budget to see more):`
        : `AVAILABLE PRODUCTS (most relevant first):`;
    productContext = `${heading}\n${lines}\n\nRULES:\n- Only mention products listed.\n- NEVER tell the customer how many units are in stock. Do not mention quantities or numbers of items left.\n- Only say a product is "out of stock" when it is marked Out of stock above.\n- Do NOT write any image URLs, links, or "Image:" lines — the system attaches the photo automatically.`;

    if (sizeColorOOS) {
      productContext += `\n- The exact size/colour the customer asked for is currently OUT OF STOCK. Tell them gently and offer the closest available size or colour from the list.`;
    } else if (sizeNotCarried) {
      productContext += `\n- We have this item, but NOT in the exact size/colour the customer asked for. Say so kindly and tell them which sizes/colours ARE available from the list above.`;
    }

    if (isBrowse) {
      const cats = [...new Set(products.map(p => p.category).filter(Boolean))].slice(0, 12);
      if (cats.length) productContext += `\n- We also sell these types of items: ${cats.join(', ')}. Mention them naturally in everyday words (not as a keyword list) and invite the customer to say what they're looking for.`;
    }

    // The customer wants to SEE a product — keep the bot from prematurely taking an order.
    if (wantsImage && !base.isOrderIntent && searchMode === 'text' && !isBrowse) {
      productContext += `\n- The customer wants to SEE this product, not necessarily buy it. Show the item and its price. Do NOT ask for name, address or payment unless they say they want to order.`;
    }

    if (base.isImageSearch && stockAsk) {
      productContext += topMatchOOS
        ? `\n- The customer asked if the item in the photo is available. The closest visual match is OUT OF STOCK — say so plainly, then offer the most similar IN-STOCK option from the list above (if any).`
        : `\n- The customer asked if the item in the photo is available. Lead your reply with a clear yes/no on the best-matching item, then give its price.`;
    }

    // Deterministic image pick: best-ranked product that actually has an image.
    // Attach for image search or when a SPECIFIC item was asked to be shown —
    // never for a broad "show me everything" browse (no single item is meant).
    if ((base.isImageSearch || wantsImage) && !isBrowse) {
      const pool = top.map(x => x.p);
      let chosen = null;
      if (base.isImageSearch && stockAsk && topMatchOOS) {
        chosen = pool.find(p => inStockOf(p) && (p.image_urls || [])[0]) || null; // show what they can buy
      }
      if (!chosen) chosen = pool.find(p => (p.image_urls || [])[0]) || null;
      if (chosen) { pendingImageUrl = (chosen.image_urls || [])[0]; pendingImageCaption = chosen.name; }
      else if (wantsImage) {
        // matched a product, but no photo on file — don't imply the item doesn't exist
        productContext += `\n- No photo is on file for the matched item(s). Share the name and price, and apologise that a photo isn't available. Do NOT say the product itself is unavailable.`;
      }
    }
  }
}

// ── FOLLOW-UP "send me a photo" (no fresh product match this turn) ──────────
// If the customer asks to see a photo on its own ("can u send a image"), attach
// the photo of the most recent product we showed them in this conversation.
// Without this, a two-step flow ("looking for a frock" -> "send a photo")
// attaches nothing and the model wrongly claims it can't send images.
if (wantsImage && !pendingImageUrl && !isBrowse && !base.isImageSearch && !base.isDeliveryIntent && !base.isCategoryQuery) {
  const recentAssistant = chatHistory.filter(m => m.role === 'assistant').slice(-6).reverse();
  const namedWithPhoto = [...products]
    .filter(p => (p.image_urls || [])[0])
    .sort((a, b) => (b.name || '').length - (a.name || '').length);  // longest name wins
  let recalled = null;
  for (const msg of recentAssistant) {
    const txt = normWords(msg.content);
    recalled = namedWithPhoto.find(p => p.name && txt.includes(normWords(p.name)));
    if (recalled) break;
  }
  if (recalled) {
    pendingImageUrl = (recalled.image_urls || [])[0];
    pendingImageCaption = recalled.name;
    productContext += `\n\nThe customer asked to see a photo of the ${recalled.name}. Its photo IS being sent with your reply — introduce it warmly (e.g. "Here's the ${recalled.name} :)") and give its price. NEVER say you cannot send images.`;
  } else {
    productContext += `\n\nThe customer asked for a photo but no specific item is in context. Politely ask which product they'd like to see — do NOT say you cannot send photos.`;
  }
}

// ── DELIVERY CONTEXT ────────────────────────────────────
let deliveryContext = '';
if (base.isDeliveryIntent) {
  const deliveryRes = $('HTTP — GET /api/v1/delivery').first().json;
  if (base.detectedCity) {
    const zone = deliveryRes.zone;
    if (zone && zone.is_active) {
      const free = zone.free_delivery_threshold > 0
        ? ` Free delivery above LKR ${zone.free_delivery_threshold.toLocaleString()}.` : '';
      deliveryContext = `DELIVERY TO ${base.detectedCity.toUpperCase()}:\nFee: LKR ${zone.fee} | Time: ${zone.estimated_days} days${free}`;
    } else {
      deliveryContext = `DELIVERY: No zone set up for ${base.detectedCity}. Tell customer to contact us directly.`;
    }
  } else {
    const zones = (deliveryRes.zones || []).filter(z => z.is_active).slice(0, 8);
    if (zones.length > 0) {
      const zoneLines = zones.map(z => `• ${z.district}: LKR ${z.fee} (${z.estimated_days} days)`).join('\n');
      deliveryContext = `DELIVERY ZONES:\n${zoneLines}\nTell customer to share their city for exact fee.`;
    } else {
      deliveryContext = 'DELIVERY: We deliver island-wide. Ask customer for their city.';
    }
  }
}

// ── COMBINE AND BUILD GEMINI PAYLOAD ─────────────────────
// ── CATEGORY QUESTION ("what do you sell / what categories") ──
let categoryContext = '';
if (base.isCategoryQuery) {
  const cats = [...new Set(products.filter(p => p.is_active !== false).map(p => p.category).filter(Boolean))];
  categoryContext = cats.length
    ? `THE SHOP SELLS THESE TYPES OF ITEMS: ${cats.join(', ')}.\nTell the customer what you have the way a warm, real shop assistant would — one short, friendly, natural sentence in their language. Do NOT list them as keywords, bullet points, or technical words. Put any technical-sounding category into everyday words a shopper uses. Then warmly ask what they are looking for.`
    : `The shop has no categories set up yet. Warmly ask the customer what they are looking for.`;
}

let orderStatusContext = '';
if (base.isOrderStatus && !base.orderRef) {
  orderStatusContext = `ORDER STATUS REQUEST (no Order ID provided): The customer is asking about an existing order but gave no Order ID. Politely ask them to share it (it looks like ORD-2026-0042). Do NOT guess, assume, or invent any status, items, total, tracking number or delivery date.`;
}

const contextParts = [kbContext, categoryContext, productContext, deliveryContext, orderStatusContext].filter(c => c.trim());
const finalContext = contextParts.length > 0
  ? contextParts.join('\n\n---\n\n') + '\n\nAnswer ONLY based on the above. Do not invent details. Keep replies SHORT and conversational for WhatsApp.'
  : fallbackMsg;

// ── CHAT-TO-ORDER PROTOCOL ──────────────────────────────
// ── ORDER-EDIT PERMISSION (depends on live dashboard status) ──────
const supportLine = supportNumber
  ? `ask them to contact our team on ${supportNumber} for any change.`
  : `ask them to contact our support team directly for any change.`;
let editingRule;
if (orderState === 'locked') {
  editingRule = `EDITING A CONFIRMED ORDER: The customer's order has ALREADY BEEN CONFIRMED by our team from the dashboard. It can no longer be changed through chat. If they ask to change items, quantities, address or payment, gently tell them the order is already confirmed and ${supportLine} Do NOT collect changes, do NOT show a new summary, and do NOT output any order block.`;
} else if (orderState === 'cancelled') {
  editingRule = `EDITING A CANCELLED ORDER: The customer's previous order was cancelled. If they want to change or re-order, tell them the earlier order was cancelled and help them place a fresh order from scratch if they wish. Do NOT try to edit the cancelled order.`;
} else if (orderState === 'editable') {
  editingRule = `EDITING AN UNCONFIRMED ORDER: The customer's order is NOT yet confirmed by our team, so changes ARE allowed. If they want to change items, quantities, address or payment, collect the changes, show the updated summary and ask them to confirm again. Once they confirm, their existing order is updated on our system automatically (same order, no duplicate) — tell them warmly that their order has been updated.`;
} else {
  // unknown / none → keep the safe original behaviour
  editingRule = `EDITING AN UNCONFIRMED ORDER: If the customer wants to change items, quantities, address or payment BEFORE confirming, just collect the changes, show the updated summary and ask them to confirm again. The system updates their existing pending order automatically — it will NOT create a duplicate. If they try to change an order that is already confirmed, tell them it is confirmed and can no longer be changed, and ${supportLine}`;
}

const orderProtocolFull = `ORDER-TAKING PROTOCOL (Chat-to-Order):
When the customer wants to buy or has finished choosing products, guide them to place an order.
STEP 1 - Collect ALL of these. Politely ask for any that are still missing (one or two at a time):
  - Full name
  - Delivery address (including city)
  - Contact number
  - Payment method (Cash on Delivery, Bank Transfer, Card Payment, or another option)
STEP 2 - Show a clear ORDER SUMMARY: list every product with its quantity and unit price, then the subtotal, the delivery fee (use the delivery info above for their city; if the city is unknown, ask for it), and the TOTAL. Restate the name, address and payment method.
STEP 3 - After you have shown the full order summary, ask the customer to confirm. A clear yes in ANY language counts as confirmation — for example: "Confirm Order", "yes", "yeah", "ok", "okay", "confirm", "correct", "go ahead", "ha", "howa", "hari", "oni", "ඔව්", "හරි", "ஆம்", "சரி". Only treat a yes as confirmation when you have JUST shown a complete order summary and are waiting for their go-ahead; if instead they want to change something, collect the change and show an updated summary.
STEP 4 - Do NOT place the order until the customer has clearly agreed to the summary you just showed. A clear yes in any language (see STEP 3) IS that agreement — do not keep demanding the exact words "Confirm Order". Never invent prices - only use prices shown above or already quoted earlier in this chat. Keep the conversation in the customer's language.

DELIVERY FEE: Always take the delivery fee from the DELIVERY info above for the customer's city — never invent or estimate it. If the city is unknown, ask for it before showing a total. The dashboard records the final fee.
${editingRule}

ONLY AFTER the customer has explicitly confirmed, end your message with this EXACT machine block (the customer never sees it):
###PLACE_ORDER###
{"customer_name":"...","delivery_address":"...","contact_number":"...","payment_method":"...","currency":"LKR","delivery_fee":0,"items":[{"name":"...","variant":"...","quantity":1,"unit_price":0}]}
###END_ORDER###
Block rules: valid JSON on a SINGLE line; numbers only (no currency symbols or commas); use "" for variant when none; put your friendly confirmation text BEFORE the block; output the block at most once; never output it before the customer confirms.`;

const orderProtocol = alreadyOrdered
  ? `IMPORTANT — AN ORDER HAS ALREADY BEEN PLACED in this conversation. Do NOT place another order and do NOT output any ###PLACE_ORDER### block for greetings, thanks, questions, or small talk. ONLY output a new block if the customer EXPLICITLY asks to change their order (different items, quantity, address, or payment) and then confirms again — in that case re-collect the details, show the updated summary, and output exactly one block. If they ask about delivery status, tell them you'll check and ask for their Order ID. Otherwise just reply warmly in their language.`
  : orderProtocolFull;

const systemPrompt = `${base.systemBase}\n\nLANGUAGE RULE: ${base.langRule}\n\nIMPORTANT: You are a warm, real human shop assistant chatting on WhatsApp — never sound like a bot or an AI. Write short, natural, friendly sentences the way a helpful shopkeeper texts. Do NOT dump keyword lists, bullet points, or technical words (category codes, SKUs, system terms); describe things in plain everyday words. Keep replies short, no markdown headers, emojis sparingly, never output URLs or links, and never reveal exact stock quantities. PHOTOS: When a product photo is on file, the system automatically attaches it to your reply — so NEVER tell the customer you can't send images or photos. If they ask to see an item we carry, just introduce it warmly and the photo will be sent alongside your message. GROUNDING: Only say an item is available if it appears in the product information below. If it is not listed there, tell the customer we don't have it — never claim, imply, promise, show a price for, or start an order for an item that is not listed, even if the customer says yes or insists. If the listed item is different from what they asked for, do not pretend it is the same item.\n\n${finalContext}\n\n${orderProtocol}`;

const historyMessages = chatHistory.map(m => ({
  role:  m.role === 'assistant' ? 'model' : 'user',
  parts: [{ text: m.content || '' }]
}));

// For image searches with no text caption, give the model an explicit instruction.
const effectiveUserMessage = base.isImageSearch && !base.userMessage
  ? '[The customer sent a product photo. Use the VISUALLY SIMILAR PRODUCTS context to help them.]'
  : base.userMessage;

const geminiPayload = {
  systemInstruction: { role: 'system', parts: [{ text: systemPrompt }] },
  contents: [
    ...historyMessages,
    { role: 'user', parts: [{ text: effectiveUserMessage }] }
  ],
  generationConfig: {
    temperature:     0.4,
    maxOutputTokens: 1200,
    thinkingConfig:  { thinkingBudget: 512 }
  }
};

return [{ json: {
  ...base,
  geminiPayload,
  wantsImage,
  pendingImageUrl,
  pendingImageCaption,
  searchMode,
  searchResults,
  alreadyOrdered,
  noMatch,
  orderState,
  currentOrderRef,
  supportNumber
} }];

const ctx       = $('Code — Build Context').first().json;
const geminiRes = $input.first().json;

const candidate = geminiRes.candidates?.[0];
if (geminiRes.error || !candidate) {
  throw new Error('GEMINI_ERROR: ' + (geminiRes.error?.message || 'No candidates'));
}

let botReply = (candidate.content?.parts || []).map(p => p.text || '').join('').trim();

// Gemini can finish on MAX_TOKENS (thinking ate the budget) or safety and return
// empty/partial text. Don't send a blank or half message — fall back cleanly.
const finish = candidate.finishReason || '';
if (!botReply && (finish === 'MAX_TOKENS' || finish === 'SAFETY' || finish === 'RECITATION')) {
  botReply = ctx.pendingImageCaption
    || 'Sorry, could you please repeat that? 🙂';
}


// ── CHAT-TO-ORDER: detect the machine block ────────────────────
let isOrder = false;
let orderPayload = null;
let orderError = null;
const orderMatch = botReply.match(/###PLACE_ORDER###([\s\S]*?)###END_ORDER###/i);
if (orderMatch) {
  botReply = botReply.replace(orderMatch[0], '').trim();   // hide from customer
  try {
    const raw = JSON.parse(orderMatch[1].trim());
    const items = (raw.items || []).map(it => {
      const qty  = Number(it.quantity)   || 0;
      const unit = Number(it.unit_price) || 0;
      return {
        name:       String(it.name || '').trim(),
        variant:    String(it.variant || '').trim(),
        quantity:   qty,
        unit_price: unit,
        line_total: qty * unit
      };
    }).filter(it => it.name && it.quantity > 0);
    if (items.length > 0) {
      const subtotal    = items.reduce((s, it) => s + it.line_total, 0);
      const deliveryFee = Number(raw.delivery_fee) || 0;
      isOrder = true;
      orderPayload = {
        customer_name:    String(raw.customer_name    || '').trim(),
        delivery_address: String(raw.delivery_address || '').trim(),
        contact_number:   String(raw.contact_number   || ctx.from || '').trim(),
        payment_method:   String(raw.payment_method   || '').trim(),
        currency:         raw.currency || 'LKR',
        items,
        subtotal,
        delivery_fee:     deliveryFee,
        total:            subtotal + deliveryFee
      };
    }
  } catch (e) {
    orderError = 'ORDER_PARSE_FAILED: ' + e.message;
  }
}

// Remove any stray URL / "Image:" the model added so the WhatsApp caption stays clean.
botReply = botReply
  .replace(/(https?:\/\/[^\s]+)/gi, '')
  .replace(/image\s*:/gi, '')
  .replace(/[ \t]+\n/g, '\n')
  .replace(/\n{2,}/g, '\n')
  .trim();

// Image decision is deterministic, from Build Context.
const imageUrl    = isOrder ? null : (ctx.pendingImageUrl || null);
const hasImageUrl = !!imageUrl;

// Clean text for the WhatsApp caption / text body.
const textReply = botReply || (isOrder ? 'Placing your order now…' : (ctx.pendingImageCaption || 'Here you go 🙂'));

// For the WEBSITE DASHBOARD we keep the image URL inside the saved message so it renders.
// WhatsApp does NOT use this field, so its caption stays clean.
const dashboardContent = hasImageUrl ? `${textReply}\n${imageUrl}` : textReply;

return [{ json: {
  ...ctx,
  botReply: textReply,        // clean text (used by WhatsApp text body)
  textReply,                  // clean text (used by WhatsApp image caption)
  dashboardContent,           // text + image url (used by dashboard save)
  hasImageUrl,
  imageUrl,
  isOrder,
  orderPayload,
  orderError,
  tokensUsed: (geminiRes.usageMetadata?.totalTokenCount || 0) + ($('Code — Detect Language + Route').first().json.understandTokens || 0)
} }];

