const lang = ext.lang || 'EN';

// Dashboard is the source of truth: trust the API echo, fall back to local only if absent.
const num = (a, b) => (a != null ? Number(a) : Number(b || 0));
const cur = op.currency || res.currency || 'LKR';
const fmt = n => `${cur} ${Number(n || 0).toLocaleString()}`;

const orderId = res.order_id || res.order_ref || res.id || op.order_ref || 'PENDING';
const locked  = res.error === 'order_locked' || res.status === 'order_locked';
const updated = res.mode === 'updated';

const subtotal = num(res.subtotal, op.subtotal);
const fee      = num(res.delivery_fee, op.delivery_fee);
const total    = num(res.total, op.total);

const items = (res.items && res.items.length ? res.items : op.items) || [];
const lines = items.map(it => {
  const v  = it.variant ? ` (${it.variant})` : '';
  const lt = it.line_total != null ? it.line_total : (Number(it.quantity || 0) * Number(it.unit_price || 0));
  return `• ${it.name}${v} × ${it.quantity} = ${fmt(lt)}`;
}).join('\n');

const L = {
