// Reads the downloaded WhatsApp image (binary) and prepares it for search.
// Resolves real bytes via the binary helper so it works in ANY n8n storage mode
// (memory / filesystem / external). Reading bin.data directly breaks when binaries
// are offloaded — it returns the marker "database" instead of the image.
const det = $('Code — Detect Language + Route').first().json;

let base64 = null, mime = det.mediaMime || 'image/jpeg';
try {
  const binMeta = $input.first().binary?.data;            // binary property is named "data"
  if (binMeta) {
    mime = binMeta.mimeType || mime;
    const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
    base64 = buffer.toString('base64');                   // genuine base64, no data: prefix
  }
} catch (e) { /* no binary — handled downstream as "unavailable" */ }

const dataUrl = base64 ? `data:${mime};base64,${base64}` : null;

return [{ json: {
  base64,
  mime,
  dataUrl,
  tenantId: det.tenantId,
  caption:  det.userMessage || ''
} }];

