parameters.jsCode:
// STRICT image search: only confident catalog matches survive. No guessing.
// - Confidence gate (MIN_SIM) rejects weak embedding matches.
// - Vision-keyword fuzzy fallback is REMOVED — if embeddings find nothing, we say
//   we don't stock it (rather than describing the photo and guessing a lookalike).
const det = $('Code — Detect Language + Route').first().json;
let prep = {};
try { prep = $('Code — Prep Image Query').first().json || {}; } catch (e) {}

const MIN_SIM = 0.60;   // confidence bar — calibrate with real photos (raise toward 0.7 if still loose)

const out = {
  isImageSearch: !!det.isImageSearch,
  matches: [],
  visionKeywords: [],   // intentionally unused in strict mode
  unavailable: false,   // true ONLY when the photo couldn't be processed (system issue)
  noStock: false        // true when search worked but nothing we sell matches
};

if (!det.isImageSearch) return [{ json: out }];   // text path — inert

// Could the photo even be read?
if (!prep.base64) { out.unavailable = true; return [{ json: out }]; }

// Embedding endpoint result
let emb = null;
try { emb = $('HTTP — Product Image Search').first().json; } catch (e) {}

// If the endpoint errored / returned no array, treat as a SYSTEM issue (don't claim we lack the item).
if (!emb || !Array.isArray(emb.matches)) { out.unavailable = true; return [{ json: out }]; }

// Keep only confident matches.
out.matches = emb.matches
  .map(m => ({
    product_id:       m.product_id || m.id || null,
    name:             m.name || '',
    image_url:        m.image_url || m.image || null,
    similarity_score: Number(m.similarity_score ?? m.score ?? 0)
  }))
  .filter(m => m.similarity_score >= MIN_SIM)
  .sort((a, b) => b.similarity_score - a.similarity_score);

out.noStock = out.matches.length === 0;   // searched fine, nothing matched → we don't sell it
return [{ json: out }];

