        notFound:r=>`${r} என்ற ஆர்டர் எண் கிடைக்கவில்லை. தயவுசெய்து எண்ணை சரிபார்த்து மீண்டும் முயற்சிக்கவும்.`,
        statuses:{pending:'உறுதிசெய்ய நிலுவையில்',confirmed:'உறுதிசெய்யப்பட்டது',preparing:'தயாராகிறது',shipped:'அனுப்பப்பட்டது',delivered:'வழங்கப்பட்டது',cancelled:'ரத்து'} },
