parameters.jsCode:
const meta  = $('Code — Detect Language + Route').first().json;
const order = $('HTTP — Get Awaiting-Payment Order').first().json.order || {};

const item = $input.first();
const bin  = item.binary || {};
const key  = Object.keys(bin)[0] || null;

// Read the ACTUAL bytes via the binary helper. item.binary[key].data may only be a
// storage-mode stub (e.g. 'database'/'filesystem') when n8n isn't storing binary inline,
// so reaching into .data can yield garbage. getBinaryDataBuffer works in every mode.
let fileBase64 = null;
if (key) {
  try {
    const buff = await this.helpers.getBinaryDataBuffer(0, key);
    fileBase64 = buff.toString('base64');
  } catch (e) {
    const inline = bin[key].data;
    fileBase64 = (inline && inline !== 'database' && inline.length > 100) ? inline : null;
  }
}

const mimeType = (key && bin[key].mimeType) || meta.mediaMime || 'application/octet-stream';
const fileName = (key && bin[key].fileName) || meta.mediaFilename || ('proof_' + (order.order_ref || Date.now()));

// Prefer an ORD reference typed in the caption; else the order's own ref.
const caption = meta.userMessage || '';
const m = caption.match(/ORD[-\s]?\d{4}[-\s]?\d{3,}/i);
const customerReference = m ? m[0].toUpperCase().replace(/\s+/g,'-').replace(/-+/g,'-') : (order.order_ref || null);

return [{ json: { ...meta, orderId: order.id, orderRef: order.order_ref, fileBase64, mimeType, fileName, customerReference } }];

