const lang   = (raw.language || 'EN').toUpperCase();
const status = raw.new_status;
const ref    = raw.order_ref || raw.order_id || 'your order';
const name   = raw.customer_name || '';
const cur    = raw.currency || 'LKR';
const total  = `${cur} ${Number(raw.total || 0).toLocaleString()}`;
const reason = (raw.reason || '').trim();

// Only notify on terminal payment decisions.
const sendable = status === 'confirmed' || status === 'cancelled';

const T = {
  confirmed: {
    EN: `✅ *Payment Confirmed!*\n\nHi ${name}, your payment for *${ref}* has been verified.\nTotal: ${total}\n\nWe’re now preparing your order. Thank you! 🙏`,
    SI: `✅ *ගෙවීම තහවුරු විය!*\n\nආයුබෝවන් ${name}, *${ref}* සඳහා ඔබගේ ගෙවීම තහවුරු කරන ලදී.\nමුළු මුදල: ${total}\n\nඅපි දැන් ඔබගේ ඇණවුම සූදානම් කරමින් සිටිමු. ස්තූතියි! 🙏`,
    TA: `✅ *கட்டணம் உறுதிசெய்யப்பட்டது!*\n\nவணக்கம் ${name}, *${ref}* க்கான உங்கள் கட்டணம் சரிபார்க்கப்பட்டது.\nமொத்தம்: ${total}\n\nஉங்கள் ஆர்டரை இப்போது தயாரிக்கிறோம். நன்றி! 🙏`,
    SL: `✅ *Payment Confirm una!*\n\nHi ${name}, *${ref}* sandaha oyage payment eka verify una.\nTotal: ${total}\n\nApi dæn oyage order eka hadanawa. Stuti! 🙏`
  },
  cancelled: {
    EN: `❌ *Payment Not Verified*\n\nHi ${name}, we could not verify the payment for *${ref}*.${reason ? '\nReason: ' + reason : ''}\n\nPlease re-upload your payment slip or contact us for help. 🙏`,
    SI: `❌ *ගෙවීම තහවුරු නොවීය*\n\nආයුබෝවන් ${name}, *${ref}* සඳහා ගෙවීම තහවුරු කළ නොහැකි විය.${reason ? '\nහේතුව: ' + reason : ''}\n\nකරුණාකර ඔබගේ ගෙවීම් රිසිට්පත නැවත එවන්න හෝ අප හා සම්බන්ධ වන්න. 🙏`,
    TA: `❌ *கட்டணம் சரிபார்க்கப்படவில்லை*\n\nவணக்கம் ${name}, *${ref}* க்கான கட்டணத்தைச் சரிபார்க்க முடியவில்லை.${reason ? '\nகாரணம்: ' + reason : ''}\n\nஉங்கள் கட்டண ரசீதை மீண்டும் அனுப்பவும் அல்லது எங்களைத் தொடர்பு கொள்ளவும். 🙏`,
    SL: `❌ *Payment Verify une na*\n\nHi ${name}, *${ref}* sandaha payment eka verify karanna bæ una.${reason ? '\nReason: ' + reason : ''}\n\nPayment slip eka aaye evanna nætnam apita message karanna. 🙏`
  }
};

const body = sendable ? ((T[status] || {})[lang] || (T[status] || {}).EN || '') : '';

return [{ json: {
  sendable,
  to:            raw.customer_phone,
  phoneNumberId: tenant.phone_number_id,
  waAccessToken: tenant.wa_access_token,
  tenantId:      raw.tenant_id,
  orderRef:      ref,
  newStatus:     status,
  body
} }];

