parameters.jsCode:
// Normalise the customer's current order into a simple, safe shape for Build Context.
// Endpoint contract (flowbot backend):
//   GET /api/v1/orders/current?tenant_id=&phone=
//   -> { order: { order_ref, status }, support_number? }   (order:null when none)
// Degrades gracefully: if the endpoint is missing/errors, we output an "unknown"
// state and Build Context falls back to its previous behaviour (no regression).
let res = {};
try { res = $input.first().json || {}; } catch (e) { res = {}; }

const order = res.order || (Array.isArray(res.orders) ? res.orders[0] : null) || null;
const statusRaw = String((order && (order.status || order.state)) || '').toLowerCase().trim();

// Real OrderStatus enum (8 values) — aligned with backend lib/db/orders.ts.
// Editable: customer may still change via chat. Locked: team-confirmed, no edits.
const EDITABLE = ['pending', 'awaiting_payment', 'pending_verification'];
const LOCKED   = ['confirmed', 'preparing', 'shipped', 'delivered'];

let orderState;                 // 'none' | 'editable' | 'locked' | 'cancelled' | 'unknown'
if (!order)                          orderState = 'none';
else if (statusRaw === 'cancelled' || statusRaw === 'canceled') orderState = 'cancelled';
else if (LOCKED.includes(statusRaw)) orderState = 'locked';
else if (EDITABLE.includes(statusRaw)) orderState = 'editable';
else                                 orderState = 'unknown';

// Support number: reuse whatever contact the backend already stores.
// Try the order endpoint first, then chatbot_settings from get_config.
let supportNumber = res.support_number || res.support_contact || res.contact_number || '';
if (!supportNumber) {
  try {
    const cs = $('HTTP — n8n get_config').first().json.chatbot_settings || {};
    supportNumber = cs.support_number || cs.support_phone || cs.contact_number || cs.whatsapp_support || cs.hotline || '';
  } catch (e) {}
}

return [{ json: {
  currentOrderRef: (order && (order.order_ref || order.order_id)) || null,
  orderStatus:     statusRaw || null,
  orderState,
  supportNumber:   String(supportNumber || '').trim()
} }];

const ext = $('Code — Extract Reply').first().json;
const upd = $('HTTP — Update Order').first().json || {};
const lang = ext.lang || 'EN';
const supportNumber = (ext.supportNumber || '').trim();
const cur = (ext.orderPayload && ext.orderPayload.currency) || 'LKR';
const fmt = n => `${cur} ${Number(n || 0).toLocaleString()}`;

const locked = upd.error === 'order_locked';
const ok = upd.ok === true && upd.order;

// Unexpected shape (network hiccup / 500) — the backend guarantees it never
// touches the row on failure, so just keep the LLM's own reply rather than
// invent a status we don't actually know.
if (!locked && !ok) {
  return [{ json: ext }];
}

const SUPPORT_LINE = supportNumber
  ? {
      EN: `Please contact us on ${supportNumber} for any change.`,
      SI: `වෙනසක් අවශ්‍ය නම් කරුණාකර ${supportNumber} අංකයට අප හා සම්බන්ධ වන්න.`,
      TA: `மாற்றத்திற்கு தயவுசெய்து ${supportNumber} எண்ணில் எங்களைத் தொடர்பு கொள்ளவும்.`,
      SL: `Mokakwath change karanna one nam ${supportNumber} number ekata call karanna.`,
    }
  : {
      EN: `Please contact our support team directly for any change.`,
      SI: `වෙනසක් අවශ්‍ය නම් කරුණාකර අපගේ සහාය කණ්ඩායම හා සම්බන්ධ වන්න.`,
      TA: `மாற்றத்திற்கு தயவுசெய்து எங்கள் ஆதரவுக் குழுவை நேரடியாக தொடர்பு கொள்ளவும்.`,
      SL: `Mokakwath change karanna one nam direct-ma support team ekata message karanna.`,
    };

if (locked) {
  const ref = upd.order_ref || ext.currentOrderRef || 'your order';
  const L = {
    EN: `⚠️ Sorry, *${ref}* has already been confirmed by our team and can no longer be changed here. ${SUPPORT_LINE.EN}`,
    SI: `⚠️ සමාවෙන්න, *${ref}* දැනටමත් අපගේ කණ්ඩායම විසින් තහවුරු කර ඇති නිසා මෙතැනින් වෙනස් කළ නොහැක. ${SUPPORT_LINE.SI}`,
    TA: `⚠️ மன்னிக்கவும், *${ref}* ஏற்கனவே எங்கள் குழுவால் உறுதிப்படுத்தப்பட்டதால் இங்கு மாற்ற முடியாது. ${SUPPORT_LINE.TA}`,
    SL: `⚠️ Sorry, *${ref}* dæntamath api team eken confirm karala, methanin change karanna bæ. ${SUPPORT_LINE.SL}`,
  };
  const body = L[lang] || L.EN;
  return [{
    json: {
      ...ext,
      botReply: body,
      textReply: body,
      dashboardContent: body,
      isOrder: false,
      orderLocked: true,
    },
  }];
}

// Success — the server-recomputed total is authoritative. The LLM wrote its
// own "updated summary" text before this call using its own (occasionally
// wrong) math, so reconcile if the server total disagrees.
const serverTotal = upd.order.total;
const llmTotal = ext.orderPayload ? Number(ext.orderPayload.total) : null;
let body = ext.botReply || '';

if (llmTotal != null && Math.abs(llmTotal - Number(serverTotal)) > 0.5) {
  const NOTE = {
    EN: `\n\n(Confirmed total: ${fmt(serverTotal)})`,
    SI: `\n\n(තහවුරු කළ මුළු මුදල: ${fmt(serverTotal)})`,
    TA: `\n\n(உறுதிப்படுத்தப்பட்ட மொத்தம்: ${fmt(serverTotal)})`,
    SL: `\n\n(Confirm una total eka: ${fmt(serverTotal)})`,
  };
  body += (NOTE[lang] || NOTE.EN);
}

return [{
  json: {
    ...ext,
    botReply: body,
    textReply: body,
    dashboardContent: body,
    currentOrderRef: upd.order.order_ref || ext.currentOrderRef,
  },
}];

const base = $('Code — Detect Language + Route').first().json;
let res = {};
try { res = $input.first().json || {}; } catch (e) { res = {}; }

const current = res.order || null;
// Explicit ref in this message wins; otherwise use the order already
// on file for this phone number so a plain "any update on my order?"
// doesn't get treated like a first-time stranger.
const orderRef = base.orderRef || (current && current.order_ref) || '';

return [{ json: {
  ...base,
  orderRef,
  resolvedFromPhone: !base.orderRef && !!orderRef
} }];
